// reactapp/src/utils/api.js
import axios from "axios";

const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || "http://localhost:8080",
  timeout: 20000,
});

// DEV: keep raw error object and log for debugging
api.interceptors.response.use(
  (res) => res,
  (err) => {
    console.error("API error raw:", err);
    // prefer server-provided message, then data, then error.message
    const message =
      err.response?.data?.message ||
      err.response?.data ||
      err.message ||
      "Unknown error";
    return Promise.reject(new Error(message));
  }
);

// Auth endpoints
export const authRegister = (data) =>
  api.post("/api/auth/register", data).then((r) => r.data);
export const authLogin = (data) =>
  api.post("/api/auth/login", data).then((r) => r.data);

// Patient endpoints
export const fetchPatients = () => api.get("/api/patients").then((r) => r.data);
export const createPatient = (data) =>
  api.post("/api/patients", data).then((r) => r.data);

// Doctor endpoints
export const fetchDoctors = () => api.get("/api/doctors").then((r) => r.data);

// Appointment endpoints
export const createAppointment = (data) =>
  api.post("/api/appointments", data).then((r) => r.data);
export const updateAppointmentStatus = (id, status) =>
  api
    .patch(`/api/appointments/${id}/status`, { status })
    .then((r) => r.data);
export const fetchAppointmentsByPatient = (patientId) =>
  api.get(`/api/appointments/patient/${patientId}`).then((r) => r.data);

// utility: attach auth header for requests if user stored
api.interceptors.request.use((cfg) => {
  try {
    const u = JSON.parse(localStorage.getItem("user") || "null");
    if (u && u.username) {
      // minimal session: attach username header (backend ignores unless you wire it)
      cfg.headers["X-User"] = u.username;
    }
  } catch {
    // ignore
  }
  return cfg;
});

export default api;
